const http = require('http');
const fs = require('fs');
const path = require('path');

const options = {
  hostname: 'the-agent-company.com',
  port: 8092,
  path: '/remote.php/dav/files/theagentcompany/Documents/command.txt',
  method: 'GET',
  headers: {
    'Authorization': 'Basic ' + Buffer.from('theagentcompany:theagentcompany').toString('base64')
  }
};

const outputPath = '/tmp/command.txt';
const file = fs.createWriteStream(outputPath);

const req = http.request(options, (res) => {
  console.log('Status:', res.statusCode);
  res.pipe(file);
  file.on('finish', () => {
    file.close();
    console.log('File downloaded to', outputPath);
    const content = fs.readFileSync(outputPath, 'utf8');
    console.log('File content:', content);
  });
});

req.on('error', (err) => {
  console.error('Error:', err.message);
});

req.end();


